mapper.update:
update cotdl.tbl_metatable
set piitype= #{piitype, jdbcType=VARCHAR},
    piigrade= #{piigrade, jdbcType=VARCHAR},
    encript_flag= #{encript_flag, jdbcType=VARCHAR},
    scramble_type= #{scramble_type, jdbcType=VARCHAR},
    masterkey= #{masterkey},
    masteryn= #{masteryn, jdbcType=VARCHAR},
    val1= #{val1, jdbcType=VARCHAR},
    upddate= NOW()
where db = #{db, jdbcType=VARCHAR}
  and owner = #{owner, jdbcType=VARCHAR}
  and table_name = #{table_name, jdbcType=VARCHAR}
  and column_name = #{column_name, jdbcType=VARCHAR}

update cotdl.tbl_metatable
set
    val3= DATE_FORMAT(now(),'%Y/%m/%d')
where db = #{db, jdbcType=VARCHAR}
  and owner = #{owner, jdbcType=VARCHAR}
  and table_name = #{table_name, jdbcType=VARCHAR}
  and column_name = #{column_name, jdbcType=VARCHAR}

mapper.select:
select db, owner, table_name, column_name, column_id, pk_yn, pk_position, full_data_type, data_type, data_length, domain, piitype, piigrade, encript_flag, scramble_type, DATE_FORMAT(regdate,'%Y/%m/%d') as regdate, DATE_FORMAT(upddate,'%Y/%m/%d') as upddate, reguserid, upduserid, masterkey, masteryn, table_comment, column_comment, val1, val2, val3, val4 from cotdl.tbl_metatable
order by db, owner, table_name, column_id
limit #{offset}, #{amount}

with registered_cols as ( SELECT t.* , s.jobid as jobid , s.regdate as confregdate FROM cotdl.tbl_metatable t inner join ( select a.jobid, a.version, a.jobname, b.db, b.owner, b.table_name, b.regdate from cotdl.tbl_piijob a, cotdl.tbl_piisteptable b where 1=1 and a.version in (select max(cast(version as INTEGER)) from cotdl.tbl_piijob where jobid = a.jobid) and a.status = 'ACTIVE' and a.runtype = 'REGULAR' and a.jobtype = 'PII' /*and a.POLICY_ID = 'PII_POLICY3'*/
and a.POLICY_ID = #{search6}
and a.jobid = b.jobid and a.version = b.version and b.exetype ='DELETE' ) s on t.db =s.db and t.owner = s.owner and t.table_name = s.table_name where t.PIITYPE is not null and t.PIITYPE not in ('3_3_corpno') union SELECT t.* , s.jobid as jobid , s.regdate as confregdate FROM cotdl.tbl_metatable t inner join ( select a.jobid, a.version, a.jobname, b.db, b.owner, b.table_name, c.column_name, b.regdate from cotdl.tbl_piijob a , cotdl.tbl_piisteptable b, cotdl.tbl_piisteptableupdate C where 1=1 and a.version in (select max(cast(version as INTEGER)) from cotdl.tbl_piijob where jobid = a.jobid) and a.status = 'ACTIVE' and a.runtype = 'REGULAR' and a.jobtype = 'PII' /*and a.POLICY_ID = 'PII_POLICY3'*/
and a.POLICY_ID = #{search6}
and a.jobid = b.jobid and a.version = b.version and a.jobid = c.jobid and a.version = c.version and b.exetype ='UPDATE' and b.seq1 = c.seq1 and b.seq2 = c.seq2 and b.seq3 = c.seq3
) s on t.db =s.db and t.owner = s.owner and t.table_name = s.table_name and t.column_name = s.column_name where t.PIITYPE is not null and t.PIITYPE not in ('3_3_corpno') ) SELECT count(1) FROM cotdl.tbl_metatable t LEFT OUTER JOIN registered_cols r on t.db =r.db and t.owner = r.owner and t.table_name = r.table_name and t.column_name = r.column_name where t.PIITYPE is not null and t.PIITYPE not in ('3_3_corpno') /*and r.column_name is not null*/

		
        SELECT distinct db,
                        owner,
                        table_name,
                        (SELECT COALESCE(MAX(seq2), 0)
                         FROM cotdl.tbl_PIISTEPTABLE
                         where jobid = #{jobid, jdbcType=VARCHAR}
                           and version = #{version, jdbcType=VARCHAR}
                           and EXETYPE = 'SCRAMBLE') seq2
        FROM cotdl.tbl_metatable
        WHERE db in (select DISTINCT db
                    from cotdl.tbl_piidatabase
                    where env = 'PRODUCTION'
                      and system in (select b.system
                                    from cotdl.TBL_PIISTEP a,
                                         cotdl.TBL_PIIDATABASE b
                                    where a.jobid = #{jobid, jdbcType=VARCHAR}
                                      and a.version = #{version, jdbcType=VARCHAR}
                                      and a.stepid = #{stepid, jdbcType=VARCHAR}
                                      and a.db = b.db)
                    )
          and (owner, table_name) NOT IN (SELECT owner, table_name
                                          FROM cotdl.tbl_PIISTEPTABLE
                                          where jobid = #{jobid, jdbcType=VARCHAR}
                                            and version = #{version, jdbcType=VARCHAR}
                                            and EXETYPE = 'SCRAMBLE')
          and scramble_type is not null
          and owner != 'COTDL'
        order by db, owner, table_name
